mapper.insert:
/* 포인트 충전 주문: 행 추가 (대기 상태) */
INSERT INTO POINT_CHARGE_ORDER (USR_SN, PT_CHG_ORD_NO, PT_CHG_ORD_AMT, PT_CHG_ORD_STATUS_CD)
VALUES (#{usrSn}, #{ptChgOrdNo}, #{ptChgOrdAmt}, #{ptChgOrdStatusCd})

mapper.update:
/* 포인트 충전 주문: 완료 처리 */
UPDATE POINT_CHARGE_ORDER
SET PT_CHG_ORD_STATUS_CD = #{statusCd},
    PT_CHG_ORD_PG_KEY = #{pgKey},
    PT_LDG_SN = #{ptLdgSn}
WHERE PT_CHG_ORD_SN = #{ptChgOrdSn}

/* 포인트 충전 주문: 실패/취소 처리 */
UPDATE POINT_CHARGE_ORDER
SET PT_CHG_ORD_STATUS_CD = #{statusCd},
    PT_CHG_ORD_PG_KEY = #{pgKey},
    PT_CHG_ORD_FAIL_RSN_CN = #{failRsnCn}
WHERE PT_CHG_ORD_SN = #{ptChgOrdSn}
